ERROR - 2023-01-30 07:27:32 --> SELECT `x`.`companyID`, `x`.`elementID`, `x`.`menuElementID`, `x`.`parentMenuElementID`, `x`.`display`, `x`.`address`, `x`.`orden`, `x`.`icon`, `x`.`template`, `x`.`nivel`
FROM (`tb_menu_element` x)
JOIN `tb_element` e ON `e`.`elementID` = `x`.`elementID`
JOIN `tb_component_element` ce ON `e`.`elementID` = `ce`.`elementID`
JOIN `tb_company_component` cco ON `ce`.`componentID` = `cco`.`componentID`
WHERE `x`.`companyID` =  '2'
AND `x`.`isActive` =  1
AND `cco`.`companyID` =  '2'
